"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";

const HERO_IMAGE = "data:image/png;base64,";

export default function Login() {
  const [form, setForm] = useState({ email: "", password: "" });
  const [loading, setLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const router = useRouter();

  const handleLogin = async () => {
    if (!form.email || !form.password) {
      alert("Please fill all fields");
      return;
    }
    try {
      setLoading(true);
      const res = await fetch("/api/auth/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form),
      });
      const data = await res.json();
      if (data.error) { alert(data.error); return; }
      localStorage.setItem("user", JSON.stringify(data));
      router.push("/");
    } catch (err) {
      console.error(err);
      alert("Something went wrong");
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter") handleLogin();
  };

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@400;500;600;700;800&display=swap');

        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

        .lr-root {
          font-family: 'Plus Jakarta Sans', sans-serif;
          min-height: 100vh;
          width: 100%;
          position: relative;
          overflow: hidden;
          background: #f0f2ff;
        }

        /* Full-bleed background image */
        .lr-bg {
          position: absolute;
          inset: 0;
          width: 100%;
          height: 100%;
          object-fit: cover;
          object-position: left center;
          display: block;
          z-index: 0;
        }

        /* Right half overlay — white fade, same as in the screenshot */
        .lr-right-overlay {
          position: absolute;
          inset: 0;
          background: linear-gradient(
            to right,
            transparent 0%,
            transparent 45%,
            rgba(240,242,255,0.7) 52%,
            rgba(240,242,255,0.97) 58%,
            #f0f2ff 64%,
            #f0f2ff 100%
          );
          z-index: 1;
          pointer-events: none;
        }

        /* Right-side form panel */
        .lr-right {
          position: absolute;
          top: 0;
          right: 0;
          bottom: 0;
          width: 48%;
          display: flex;
          align-items: center;
          justify-content: center;
          z-index: 2;
          padding: 40px 48px;
        }

        .lr-form-inner {
          width: 100%;
          max-width: 360px;
          animation: fadeUp 0.5s ease forwards;
        }

        @keyframes fadeUp {
          from { opacity: 0; transform: translateY(16px); }
          to   { opacity: 1; transform: translateY(0); }
        }

        /* Brand */
        .lr-brand {
          font-size: 36px;
          font-weight: 800;
          color: #111827;
          letter-spacing: -1.2px;
          line-height: 1.1;
          margin-bottom: 6px;
        }
        .lr-brand span { color: #6366f1; }

        .lr-tagline {
          font-size: 13px;
          color: #6b7280;
          font-weight: 500;
          margin-bottom: 40px;
        }

        /* Fields */
        .lr-field { margin-bottom: 20px; }

        .lr-label {
          display: block;
          font-size: 13px;
          font-weight: 600;
          color: #374151;
          margin-bottom: 7px;
        }

        .lr-input-wrap { position: relative; }

        .lr-input {
          width: 100%;
          padding: 13px 16px;
          border: 1.5px solid #e5e7eb;
          border-radius: 12px;
          font-size: 14px;
          font-weight: 500;
          color: #111827;
          background: #ffffff;
          outline: none;
          transition: all 0.2s;
          font-family: 'Plus Jakarta Sans', sans-serif;
        }
        .lr-input::placeholder { color: #9ca3af; font-weight: 400; }
        .lr-input:focus {
          border-color: #6366f1;
          box-shadow: 0 0 0 4px rgba(99,102,241,0.1);
        }
        .lr-input-pw { padding-right: 46px; }

        .lr-pw-toggle {
          position: absolute;
          right: 14px;
          top: 50%;
          transform: translateY(-50%);
          background: none;
          border: none;
          cursor: pointer;
          color: #9ca3af;
          display: flex;
          align-items: center;
          padding: 0;
          transition: color 0.2s;
        }
        .lr-pw-toggle:hover { color: #6366f1; }

        /* Button */
        .lr-btn {
          width: 100%;
          margin-top: 8px;
          padding: 14px;
          background: linear-gradient(135deg, #6366f1, #4f46e5);
          color: white;
          border: none;
          border-radius: 12px;
          font-size: 15px;
          font-weight: 700;
          font-family: 'Plus Jakarta Sans', sans-serif;
          cursor: pointer;
          box-shadow: 0 6px 20px rgba(99,102,241,0.35);
          transition: all 0.2s;
          display: flex;
          align-items: center;
          justify-content: center;
          gap: 8px;
        }
        .lr-btn:hover:not(:disabled) {
          transform: translateY(-2px);
          box-shadow: 0 10px 28px rgba(99,102,241,0.4);
        }
        .lr-btn:disabled { opacity: 0.7; cursor: not-allowed; }

        .lr-forgot {
          text-align: center;
          margin-top: 14px;
          font-size: 13px;
          color: #6b7280;
          font-weight: 500;
          cursor: pointer;
          transition: color 0.2s;
        }
        .lr-forgot:hover { color: #6366f1; }

        .lr-footer {
          text-align: center;
          font-size: 11.5px;
          color: #9ca3af;
          margin-top: 28px;
          font-weight: 500;
        }

        @keyframes spin { to { transform: rotate(360deg); } }
        .spin { animation: spin 0.8s linear infinite; }

        @media (max-width: 768px) {
          .lr-right {
            width: 100%;
            background: rgba(240,242,255,0.97);
            padding: 40px 28px;
          }
          .lr-right-overlay { display: none; }
        }
      `}</style>

      <div className="lr-root">
        {/* Full background image */}
        <img src={HERO_IMAGE} alt="" className="lr-bg" />

        {/* White fade overlay on right half */}
        <div className="lr-right-overlay" />

        {/* Login form — floats in the right white space */}
        <div className="lr-right">
          <div className="lr-form-inner">
            <div className="lr-brand">MediCore <span>HMS</span></div>
            <p className="lr-tagline">Tech-driven Hospital Management System</p>

            <div className="lr-field">
              <label className="lr-label">Username</label>
              <div className="lr-input-wrap">
                <input
                  type="email"
                  className="lr-input"
                  placeholder="admin@hospital.com"
                  value={form.email}
                  onChange={(e) => setForm({ ...form, email: e.target.value })}
                  onKeyDown={handleKeyDown}
                  autoComplete="email"
                />
              </div>
            </div>

            <div className="lr-field">
              <label className="lr-label">Password</label>
              <div className="lr-input-wrap">
                <input
                  type={showPassword ? "text" : "password"}
                  className="lr-input lr-input-pw"
                  placeholder="••••••••"
                  value={form.password}
                  onChange={(e) => setForm({ ...form, password: e.target.value })}
                  onKeyDown={handleKeyDown}
                  autoComplete="current-password"
                />
                <button
                  type="button"
                  className="lr-pw-toggle"
                  onClick={() => setShowPassword(v => !v)}
                  tabIndex={-1}
                >
                  {showPassword ? (
                    <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.543-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l3.59 3.59m0 0A9.953 9.953 0 0112 5c4.478 0 8.268 2.943 9.543 7a10.025 10.025 0 01-4.132 5.411m0 0L21 21" />
                    </svg>
                  ) : (
                    <svg width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                      <path strokeLinecap="round" strokeLinejoin="round" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                      <path strokeLinecap="round" strokeLinejoin="round" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                    </svg>
                  )}
                </button>
              </div>
            </div>

            <button onClick={handleLogin} disabled={loading} className="lr-btn">
              {loading ? (
                <>
                  <svg className="spin" width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M4 12a8 8 0 018-8v4" />
                  </svg>
                  Signing in...
                </>
              ) : "Login"}
            </button>

            {/* <p className="lr-forgot">Forgot your password?</p> */}

            <p className="lr-footer">© {new Date().getFullYear()} MediCore HMS · Secure Portal</p>
          </div>
        </div>
      </div>
    </>
  );
}